// ─── doc-edit handler: parameter validation ──────────────────────────────────

describe("doc-edit handler: parameter validation", () => {
  let docEditHandler;

  beforeAll(() => {
    const req = createRequire(pathToFileURL(join(tmpDir, "index.js")).href);
    docEditHandler = req(
      join(tmpDir, ".chainlesschain", "skills", "doc-edit", "handler.js"),
    );
  });

  it("returns error when input_file is missing", async () => {
    const result = await docEditHandler({});
    expect(result).toHaveProperty("success", false);
    expect(result.error).toContain("input_file");
  });

  it("returns error when instruction is missing", async () => {
    const result = await docEditHandler({ input_file: "test.md" });
    expect(result).toHaveProperty("success", false);
    expect(result.error).toContain("instruction");
  });

  it("returns error when input file does not exist", async () => {
    const result = await docEditHandler({
      input_file: "/nonexistent/path/test.md",
      instruction: "Make it better",
    });
    expect(result).toHaveProperty("success", false);
    expect(result.error).toContain("Input file not found");
  });

  it("returns structured error for unsupported format", async () => {
    const fs = require("node:fs");
    const testFile = join(tmpDir, "test_unsupported.xyz");
    fs.writeFileSync(testFile, "test content", "utf-8");

    const result = await docEditHandler({
      input_file: testFile,
      instruction: "Improve this",
    });
    expect(result).toHaveProperty("success", false);
    expect(result.error).toContain(".xyz");
    expect(result).toHaveProperty("hint");
    expect(result.hint).toContain("md");
    expect(result.hint).toContain("xlsx");
  });

  it("returns error for invalid action", async () => {
    const fs = require("node:fs");
    const testFile = join(tmpDir, "test_action.md");
    fs.writeFileSync(testFile, "# Hello\n\nContent.", "utf-8");

    const result = await docEditHandler({
      input_file: testFile,
      instruction: "Fix it",
      action: "invalid-action",
    });
    expect(result).toHaveProperty("success", false);
    expect(result.error).toContain("action");
    expect(result).toHaveProperty("hint");
  });
});

// ─── doc-edit handler: md format ─────────────────────────────────────────────

describe("doc-edit handler: md format editing", () => {
  let docEditHandler;

  beforeAll(() => {
    const req = createRequire(pathToFileURL(join(tmpDir, "index.js")).href);
    docEditHandler = req(
      join(tmpDir, ".chainlesschain", "skills", "doc-edit", "handler.js"),
    );
  });

  it("produces _edited.md output file (LLM available or error)", async () => {
    const fs = require("node:fs");
    const testFile = join(tmpDir, "source_doc.md");
    fs.writeFileSync(
      testFile,
      "# Source Document\n\nOriginal content here.",
      "utf-8",
    );

    const result = await docEditHandler({
      input_file: testFile,
      instruction: "Make the tone more formal",
    });

    // LLM may or may not be available in test env, but structure must be valid
    if (result.success) {
      expect(result.output).toMatch(/_edited\.md$/);
      expect(existsSync(result.output)).toBe(true);
    } else {
      expect(result.error).toBeTruthy();
    }
  }, 20000);

  it("does not overwrite original file", async () => {
    const fs = require("node:fs");
    const testFile = join(tmpDir, "original_preserved.md");
    const originalContent = "# Original\n\nThis must not be overwritten.";
    fs.writeFileSync(testFile, originalContent, "utf-8");

    await docEditHandler({
      input_file: testFile,
      instruction: "Change everything",
    });

    // Original must be intact regardless of success/failure
    const afterContent = fs.readFileSync(testFile, "utf-8");
    expect(afterContent).toBe(originalContent);
  }, 20000);
});

// ─── doc-edit handler: xlsx/pptx Python dependency checks ────────────────────

describe("doc-edit handler: xlsx/pptx Python dependency detection", () => {
  let docEditHandler;

  beforeAll(() => {
    const req = createRequire(pathToFileURL(join(tmpDir, "index.js")).href);
    docEditHandler = req(
      join(tmpDir, ".chainlesschain", "skills", "doc-edit", "handler.js"),
    );
  });

  it("xlsx: returns error when xlsx cannot be processed (no Python, no openpyxl, or invalid file)", async () => {
    const fs = require("node:fs");
    // Create a minimal fake xlsx (not valid, just needs to exist)
    const testXlsx = join(tmpDir, "fake.xlsx");
    fs.writeFileSync(testXlsx, "PK fake xlsx content", "utf-8");

    const result = await docEditHandler({
      input_file: testXlsx,
      instruction: "Capitalize all names",
    });

    // Three possible outcomes:
    // 1. No Python → error mentions Python + hint with python.org
    // 2. No openpyxl → error mentions openpyxl + hint with pip install
    // 3. Python+openpyxl available but file is invalid → XLSX 修改失败 error (no hint required)
    if (!result.success) {
      expect(result.error).toBeTruthy();
      if (result.hint !== undefined) {
        // When hint is provided, it should relate to Python or pip
        expect(result.hint).toMatch(/python\.org|pip install/i);
      }
    }
  }, 15000);

  it("pptx: returns error with python-pptx pip hint when python-pptx not installed", async () => {
    const fs = require("node:fs");
    const testPptx = join(tmpDir, "fake.pptx");
    fs.writeFileSync(testPptx, "PK fake pptx content", "utf-8");

    const result = await docEditHandler({
      input_file: testPptx,
      instruction: "Make text more formal",
    });

    if (!result.success) {
      expect(result.error.toLowerCase()).toMatch(/python-pptx|python|pptx/);
      if (result.hint) {
        expect(result.hint).toMatch(/python\.org|pip install/);
      }
    }
  }, 15000);

  it("docx: returns structured fallback error when no pandoc/soffice available", async () => {
    const fs = require("node:fs");
    const testDocx = join(tmpDir, "fake.docx");
    fs.writeFileSync(testDocx, "PK fake docx content", "utf-8");

    const result = await docEditHandler({
      input_file: testDocx,
      instruction: "Improve grammar",
    });

    // Either succeeds (if pandoc/soffice present) or returns structured error
    if (!result.success) {
      expect(result.error).toBeTruthy();
      expect(result).toHaveProperty("hint");
      expect(result.hint.toLowerCase()).toMatch(/pandoc|libreoffice/);
    }
  }, 20000);
});
